msg.topic = `CREATE TABLE IF NOT EXISTS \`indicadores_opc\` (\`id\` INT NOT NULL AUTO_INCREMENT,\`timestamp\` DATETIME NOT NULL,\`velocidad_molino1\` FLOAT DEFAULT NULL,\`velocidad_molino6\` FLOAT DEFAULT NULL,\`balanza_cinta\` FLOAT DEFAULT NULL,\`agua_imbibicion\` FLOAT DEFAULT NULL,\`presion_molino6_este\` FLOAT DEFAULT NULL,\`presion_molino6_oeste\` FLOAT DEFAULT NULL,\`caudal_jugo_clarif\` FLOAT DEFAULT NULL,\`nivel_melado_tratado\` FLOAT DEFAULT NULL,\`nivel_melado\` FLOAT DEFAULT NULL,\`nivel_decantador1\` FLOAT DEFAULT NULL,\`nivel_decantador2\` FLOAT DEFAULT NULL,\`nivel_decantador3\` FLOAT DEFAULT NULL,\`descarga_tachos_1ra\` FLOAT DEFAULT NULL,\`descarga_tachos_2da\` FLOAT DEFAULT NULL,\`descarga_tachos_3ra\` FLOAT DEFAULT NULL,\`contador_bolsas_dia\` FLOAT DEFAULT NULL,\`silo_a\` FLOAT DEFAULT NULL,\`silo_b\` FLOAT DEFAULT NULL,\`silo_c\` FLOAT DEFAULT NULL,\`silo_e\` FLOAT DEFAULT NULL,\`presion_vapor_directo\` FLOAT DEFAULT NULL,\`presion_agua_alim\` FLOAT DEFAULT NULL,\`presion_aire\` FLOAT DEFAULT NULL,\`caudal_vapor_cald1\` FLOAT DEFAULT NULL,\`caudal_vapor_cald2\` FLOAT DEFAULT NULL,\`caudal_vapor_cald3\` FLOAT DEFAULT NULL,\`caudal_vapor_cald6\` FLOAT DEFAULT NULL,\`vapor_total\` FLOAT DEFAULT NULL,\`caudal_gas_cald2\` FLOAT DEFAULT NULL,\`caudal_gas_cald6\` FLOAT DEFAULT NULL,\`potencia_activa_siemens\` FLOAT DEFAULT NULL,\`potencia_reactiva_siemens\` FLOAT DEFAULT NULL,\`frecuencia_siemens\` FLOAT DEFAULT NULL,\`intensidad_siemens\` FLOAT DEFAULT NULL,\`potencia_activa_aeg\` FLOAT DEFAULT NULL,\`potencia_reactiva_aeg\` FLOAT DEFAULT NULL,\`frecuencia_aeg\` FLOAT DEFAULT NULL,\`intensidad_aeg\` FLOAT DEFAULT NULL,\`potencia_total\` FLOAT DEFAULT NULL,\`cv_trapiche\` FLOAT DEFAULT NULL,\`cv_usina_alta\` FLOAT DEFAULT NULL,\`cv_destileria\` FLOAT DEFAULT NULL,\`cv_aux_total\` FLOAT DEFAULT NULL,\`cv_preparacion_cania\` FLOAT DEFAULT NULL,\`caudal_vino\` FLOAT DEFAULT NULL,\`caudal_alcohol\` FLOAT DEFAULT NULL,\`caudal_jugo_dilutor\` FLOAT DEFAULT NULL,\`caudal_melaza_dilutor\` FLOAT DEFAULT NULL,PRIMARY KEY (\`id\`),UNIQUE KEY \`uk_timestamp\` (\`timestamp\`),INDEX \`idx_ts\` (\`timestamp\`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4`;
msg.payload = [];
return msg;

// Ignorar mensajes de estado de conexión
if (msg.status !== undefined || (msg.error !== undefined && msg.endpoint !== undefined)) return null;

// Log del primer mensaje real para diagnóstico
if (!flow.get('_msg_logged')) {
    node.warn('PRIMER MSG KEYS: ' + JSON.stringify(Object.keys(msg)));
    node.warn('PRIMER MSG TOPIC: ' + String(msg.topic));
    node.warn('PRIMER MSG PAYLOAD: ' + JSON.stringify(msg.payload));
    node.warn('PRIMER MSG ADDR: ' + JSON.stringify(msg.addressSpaceItems));
    flow.set('_msg_logged', true);
}

const tagMap = {
    // Trapiche
    'ns=2;s=trapiche_molino.trapiche_molino.trap_molino1_OUT': 'velocidad_molino1',
    'ns=2;s=trapiche_molino.trapiche_molino.trap_molino6_motor_velocidad': 'velocidad_molino6',
    'ns=2;s=trapiche_molino.trapiche_molino.trap_cinta_salida1': 'balanza_cinta',
    'ns=2;s=vapor.vapor.vapor_agua_imbibicion_caudal': 'agua_imbibicion',
    'ns=2;s=trapiche_molino.trapiche_molino.trap_molino6_flotacion_este': 'presion_molino6_este',
    'ns=2;s=trapiche_molino.trapiche_molino.trap_molino6_flotacion_oeste': 'presion_molino6_oeste',
    // Fabricacion
    'ns=2;s=fabrica.fabrica.Fab_jugo_clarificado_caudal': 'caudal_jugo_clarif',
    'ns=2;s=tacho2da3ra.tacho2da3ra.Tacho_melado_tratado': 'nivel_melado_tratado',
    'ns=2;s=fabrica.fabrica.Tacho_melado_evaporacion_nivel': 'nivel_melado',
    'ns=2;s=Clarificacion2.Clarificacion2.clar2_decant1_nivel': 'nivel_decantador1',
    'ns=2;s=Clarificacion2.Clarificacion2.clar2_decant2_nivel': 'nivel_decantador2',
    'ns=2;s=Clarificacion2.Clarificacion2.clar2_decant3_nivel': 'nivel_decantador3',
    'ns=2;s=Tacho1ra.Tacho1ra.Tacho_cristalizador1ra_nivel': 'descarga_tachos_1ra',
    'ns=2;s=Tacho1ra.Tacho1ra.Tacho_melado_tachos_nivel1': 'descarga_tachos_2da',
    'ns=2;s=Tacho1ra.Tacho1ra.Tacho_melado_tachos_nivel2': 'descarga_tachos_3ra',
    // Salon
    'ns=2;s=salon.salon.salon.salon_contador_dia': 'contador_bolsas_dia',
    'ns=2;s=salon.salon.salon.SILO_A_BOLSAS': 'silo_a',
    'ns=2;s=salon.salon.salon.SILO_B_BOLSAS': 'silo_b',
    'ns=2;s=salon.salon.salon.SILO_C_BOLSAS': 'silo_c',
    'ns=2;s=salon.salon.salon.SILO_E_BOLSAS': 'silo_e',
    // Caldera
    'ns=2;s=caldera.Caldera.cald_vapor_baja_presion': 'presion_vapor_directo',
    'ns=2;s=caldera.Caldera.cald_agua_aliment1_presion': 'presion_agua_alim',
    'ns=2;s=caldera.Caldera.presion_aire': 'presion_aire',
    'ns=2;s=caldera1.caldera1.cald1_vapor_caudal': 'caudal_vapor_cald1',
    'ns=2;s=caldera2.caldera2.cald2_vapor_caudal': 'caudal_vapor_cald2',
    'ns=2;s=caldera3.caldera3.cald3_vapor_caudal': 'caudal_vapor_cald3',
    'ns=2;s=caldera6.caldera6.cald6_vapor_caudal': 'caudal_vapor_cald6',
    'ns=2;s=caldera2.caldera2.cald2_gas_caudal': 'caudal_gas_cald2',
    'ns=2;s=caldera6.caldera6.cald6_gas_caudal': 'caudal_gas_cald6',
    // Usina
    'ns=2;s=siemens.siemens.siemens_potencia_activa': 'potencia_activa_siemens',
    'ns=2;s=siemens.siemens.siemens_potencia_reactiva': 'potencia_reactiva_siemens',
    'ns=2;s=siemens.siemens.siemens_frecuencia': 'frecuencia_siemens',
    'ns=2;s=siemens.siemens.siemens_Intensidad_media': 'intensidad_siemens',
    'ns=2;s=skoda.skoda.Potencia_Activa_Total_AEG': 'potencia_activa_aeg',
    'ns=2;s=skoda.skoda.Potencia_Reactiva_Total_AEG': 'potencia_reactiva_aeg',
    'ns=2;s=skoda.skoda.Frecuencia_AEG': 'frecuencia_aeg',
    'ns=2;s=skoda.skoda.Intensidad_Media_AEG': 'intensidad_aeg',
    // Consumos vapor
    'ns=2;s=vapor.vapor.vapor_trapiche_caudal': 'cv_trapiche',
    'ns=2;s=vapor.vapor.vapor_usina_alta_caudal': 'cv_usina_alta',
    'ns=2;s=vapor.vapor.vapor_destileria_caudal': 'cv_destileria',
    'ns=2;s=vapor.vapor.vapor_auxilio_caudal': 'cv_aux_total',
    'ns=2;s=vapor.vapor.vapor_reducido_caudal': 'cv_preparacion_cania',
    // Destileria
    'ns=2;s=Destileria.Destileria.dest_vino_caudal': 'caudal_vino'
};

const nodeId = msg.topic
    || (msg.addressSpaceItems && msg.addressSpaceItems[0] && msg.addressSpaceItems[0].value)
    || (msg.payload && msg.payload.nodeId && (msg.payload.nodeId.value || msg.payload.nodeId));

if (!nodeId || !tagMap[nodeId]) return null;

let rawVal = msg.payload;
if (rawVal !== null && rawVal !== undefined && typeof rawVal === 'object') {
    rawVal = (rawVal.value && rawVal.value.value !== undefined) ? rawVal.value.value
           : rawVal.value !== undefined ? rawVal.value
           : rawVal;
}

const num = parseFloat(rawVal);
if (!isNaN(num)) {
    flow.set(tagMap[nodeId], num);
}

return null;

const now = new Date();
now.setSeconds(0, 0);
const ts = now.toISOString().replace('T', ' ').substring(0, 19);

function g(k) {
    const v = flow.get(k);
    return (v === undefined || v === null || isNaN(parseFloat(v))) ? null : parseFloat(v);
}
function sql(k) { const v = g(k); return v === null ? 'NULL' : v; }

const vt = (g('caudal_vapor_cald1') || 0) + (g('caudal_vapor_cald2') || 0) +
           (g('caudal_vapor_cald3') || 0) + (g('caudal_vapor_cald6') || 0);
const pt = (g('potencia_activa_siemens') || 0) + (g('potencia_activa_aeg') || 0);

const cols = [
    'velocidad_molino1','velocidad_molino6','balanza_cinta','agua_imbibicion',
    'presion_molino6_este','presion_molino6_oeste','caudal_jugo_clarif','nivel_melado_tratado',
    'nivel_melado','nivel_decantador1','nivel_decantador2','nivel_decantador3',
    'descarga_tachos_1ra','descarga_tachos_2da','descarga_tachos_3ra','contador_bolsas_dia',
    'silo_a','silo_b','silo_c','silo_e',
    'presion_vapor_directo','presion_agua_alim','presion_aire',
    'caudal_vapor_cald1','caudal_vapor_cald2','caudal_vapor_cald3','caudal_vapor_cald6',
    'caudal_gas_cald2','caudal_gas_cald6',
    'potencia_activa_siemens','potencia_reactiva_siemens','frecuencia_siemens','intensidad_siemens',
    'potencia_activa_aeg','potencia_reactiva_aeg','frecuencia_aeg','intensidad_aeg',
    'cv_trapiche','cv_usina_alta','cv_destileria','cv_aux_total','cv_preparacion_cania',
    'caudal_vino'
];

const vals = cols.map(c => sql(c)).join(',');
const colsQ = cols.map(c => '`' + c + '`').join(',');
const upd = cols.map(c => '`' + c + '`=VALUES(`' + c + '`)').join(',');

msg.topic = 'INSERT INTO `indicadores_opc` (`timestamp`,`vapor_total`,`potencia_total`,' + colsQ +
    ',`caudal_alcohol`,`caudal_jugo_dilutor`,`caudal_melaza_dilutor`) VALUES (' +
    "'" + ts + "'," + vt + ',' + pt + ',' + vals + ',NULL,NULL,NULL)' +
    ' ON DUPLICATE KEY UPDATE `vapor_total`=VALUES(`vapor_total`),`potencia_total`=VALUES(`potencia_total`),' + upd +
    ',`caudal_alcohol`=NULL,`caudal_jugo_dilutor`=NULL,`caudal_melaza_dilutor`=NULL';
msg.payload = [];
return msg;
